import json, sys
data = json.load(sys.stdin)
# Look for R01 or path discipline
for key in data:
    if 'r01' in key.lower() or 'path' in key.lower() or 'tilde' in key.lower() or 'discipline' in key.lower():
        print(f'{key}: {json.dumps(data[key], indent=2)}')
# Also check rules
if 'rules' in data:
    for r in data['rules']:
        if 'r01' in r.get('id','').lower() or 'tilde' in r.get('id','').lower():
            print(f'Rule: {json.dumps(r, indent=2)}')
