openclaw status --json 2>&1 | python3 -c "
import json, sys
data = json.load(sys.stdin)
agents = data.get('agents', {})
for agent_id, agent in agents.items():
    if isinstance(agent, dict):
        rules = agent.get('rules', [])
        for r in rules:
            if isinstance(r, dict):
                rid = r.get('id','')
                if 'r01' in rid.lower() or 'tilde' in rid.lower() or 'path' in rid.lower():
                    print(f'{agent_id}: {json.dumps(r, indent=2)}')
    else:
        print(f'{agent_id}: (scalar: {type(agent).__name__})')
